import{f as l,D as r,o as t,c as o,a2 as s,b as p,w as n,a as i,G as d,a5 as u}from"./chunks/framework.DHYrF-q6.js";const B=JSON.parse('{"title":"AI 评估体系","description":"","frontmatter":{},"headers":[],"relativePath":"ai-product-manager/evaluation.md","filePath":"ai-product-manager/evaluation.md","lastUpdated":1781090818000}'),c={name:"ai-product-manager/evaluation.md"};function h(b,a,q,m,g,A){const e=r("Mermaid");return t(),o("div",null,[a[1]||(a[1]=s('<h1 id="ai-评估体系" tabindex="-1">AI 评估体系 <a class="header-anchor" href="#ai-评估体系" aria-label="Permalink to &quot;AI 评估体系&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p><strong>&quot;你怎么知道模型变好了？&quot;</strong>——这是 AI PM 面试中最容易被深度追问的问题，也是实际工作中最核心的能力之一。本章从 LLM-as-a-Judge、人工评估方法论、评测集构建、线上 A/B 测试统计四个维度，建立 AI PM 的系统性评估能力。</p><div class="tip custom-block"><p class="custom-block-title">学习目标</p><p>掌握 LLM 时代的评估方法论，能独立设计评估方案、构建评测数据集、解读 A/B 测试结果。</p></div><hr><h2 id="一、知识图谱" tabindex="-1">一、知识图谱 <a class="header-anchor" href="#一、知识图谱" aria-label="Permalink to &quot;一、知识图谱&quot;">​</a></h2>',6)),(t(),p(u,null,{default:n(()=>[d(e,{id:"mermaid-18",class:"mermaid",graph:"mindmap%0A%20%20root((AI%20%E8%AF%84%E4%BC%B0%E4%BD%93%E7%B3%BB))%0A%20%20%20%20%E7%A6%BB%E7%BA%BF%E8%AF%84%E4%BC%B0%0A%20%20%20%20%20%20%E8%87%AA%E5%8A%A8%E5%8C%96%E6%8C%87%E6%A0%87%0A%20%20%20%20%20%20LLM-as-a-Judge%0A%20%20%20%20%20%20%E8%AF%84%E6%B5%8B%E9%9B%86%E6%9E%84%E5%BB%BA%0A%20%20%20%20%20%20%E5%9B%9E%E5%BD%92%E6%B5%8B%E8%AF%95%0A%20%20%20%20%E4%BA%BA%E5%B7%A5%E8%AF%84%E4%BC%B0%0A%20%20%20%20%20%20%E8%AF%84%E4%BC%B0%E9%97%AE%E5%8D%B7%E8%AE%BE%E8%AE%A1%0A%20%20%20%20%20%20%E8%AF%84%E4%BC%B0%E5%91%98%E6%A0%A1%E5%87%86%0A%20%20%20%20%20%20%E4%B8%80%E8%87%B4%E6%80%A7%E6%A3%80%E9%AA%8C%0A%20%20%20%20%20%20%E7%9B%B2%E8%AF%84%E4%B8%8E%E9%87%91%E6%A0%87%E5%87%86%0A%20%20%20%20%E5%9C%A8%E7%BA%BF%E8%AF%84%E4%BC%B0%0A%20%20%20%20%20%20A%2FB%20%E6%B5%8B%E8%AF%95%E8%AE%BE%E8%AE%A1%0A%20%20%20%20%20%20%E6%A0%B7%E6%9C%AC%E9%87%8F%E8%AE%A1%E7%AE%97%0A%20%20%20%20%20%20%E7%BB%9F%E8%AE%A1%E6%98%BE%E8%91%97%E6%80%A7%0A%20%20%20%20%20%20%E5%A4%9A%E9%87%8D%E6%AF%94%E8%BE%83%E6%A0%A1%E6%AD%A3%0A%20%20%20%20%E6%8C%81%E7%BB%AD%E7%9B%91%E6%8E%A7%0A%20%20%20%20%20%20%E6%95%88%E6%9E%9C%E8%B6%8B%E5%8A%BF%E7%9C%8B%E6%9D%BF%0A%20%20%20%20%20%20%E9%80%80%E5%8C%96%E6%A3%80%E6%B5%8B%0A%20%20%20%20%20%20%E6%95%B0%E6%8D%AE%E6%BC%82%E7%A7%BB%E5%91%8A%E8%AD%A6%0A"})]),fallback:n(()=>[...a[0]||(a[0]=[i(" Loading... ",-1)])]),_:1})),a[2]||(a[2]=s(`<hr><h2 id="二、离线评估——上线前的最后一道防线" tabindex="-1">二、离线评估——上线前的最后一道防线 <a class="header-anchor" href="#二、离线评估——上线前的最后一道防线" aria-label="Permalink to &quot;二、离线评估——上线前的最后一道防线&quot;">​</a></h2><h3 id="_2-1-传统指标在-llm-时代的局限性" tabindex="-1">2.1 传统指标在 LLM 时代的局限性 <a class="header-anchor" href="#_2-1-传统指标在-llm-时代的局限性" aria-label="Permalink to &quot;2.1 传统指标在 LLM 时代的局限性&quot;">​</a></h3><p>在传统 ML 时代，准确率/精确率/召回率/F1 是金标准。但在 LLM 时代，这些指标暴露了严重不足：</p><table tabindex="0"><thead><tr><th>传统指标</th><th>在 LLM 场景中的问题</th><th>示例</th></tr></thead><tbody><tr><td><strong>准确率</strong></td><td>过于粗糙——&quot;差不多对&quot;和&quot;完全错&quot;没有区别</td><td>用户问&quot;怎么退货&quot;，AI 回答&quot;您可以退货，但需要注意运费问题&quot;——答案方向对了但缺了运费的具体规则。准确率视角下算&quot;对&quot;，但用户体验差。</td></tr><tr><td><strong>F1</strong></td><td>适合分类，不适合生成式输出评估</td><td>客服回答不是&quot;是/否&quot;选择题，F1 无法捕捉&quot;回答是否啰嗦&quot;&quot;有没有编造信息&quot;</td></tr><tr><td><strong>BLEU/ROUGE</strong></td><td>基于 n-gram 匹配，不理解语义</td><td>&quot;可以退货&quot;和&quot;支持退货退款&quot;语义相同但 BLEU 给低分——瞎给分</td></tr></tbody></table><p><strong>结论</strong>：LLM 时代的评估必须引入<strong>多维度、细粒度</strong>的方法。</p><h3 id="_2-2-llm-as-a-judge——用-ai-评估-ai" tabindex="-1">2.2 LLM-as-a-Judge——用 AI 评估 AI <a class="header-anchor" href="#_2-2-llm-as-a-judge——用-ai-评估-ai" aria-label="Permalink to &quot;2.2 LLM-as-a-Judge——用 AI 评估 AI&quot;">​</a></h3><p>用 GPT-4 作为&quot;裁判&quot;评估另一个 AI 的输出质量，是目前业界最主流的方法。但用不好会变成&quot;用一个有偏见的裁判判另一个有偏见的选手&quot;。</p><p><strong>正确做法——结构化评估 Prompt</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## 任务</span></span>
<span class="line"><span>你需要评估一段 AI 客服的回答质量。请阅读【用户问题】和【AI 回答】，在以下四个维度打分（1-5 分）：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 准确性 Accuracy：回答内容是否与参考资料一致？有没有编造？</span></span>
<span class="line"><span>2. 完整性 Completeness：是否覆盖了用户问题的所有要点？</span></span>
<span class="line"><span>3. 简洁性 Conciseness：回答是否精炼？有没有无关废话？</span></span>
<span class="line"><span>4. 友好度 Friendliness：语气是否友好、专业？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 评分标准</span></span>
<span class="line"><span>- 5 分：完美，无可挑剔</span></span>
<span class="line"><span>- 4 分：基本正确，有小改进空间</span></span>
<span class="line"><span>- 3 分：部分正确，有明显遗漏或冗余</span></span>
<span class="line"><span>- 2 分：严重错误或无关回答</span></span>
<span class="line"><span>- 1 分：完全错误或有害</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 用户问题</span></span>
<span class="line"><span>{user_query}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 参考资料（正确答案应该基于此）</span></span>
<span class="line"><span>{reference_documents}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## AI 回答</span></span>
<span class="line"><span>{ai_response}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 输出格式</span></span>
<span class="line"><span>请按以下 JSON 格式输出评分和理由：</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>  &quot;accuracy&quot;: {&quot;score&quot;: 4, &quot;reason&quot;: &quot;...&quot;},</span></span>
<span class="line"><span>  &quot;completeness&quot;: {&quot;score&quot;: 3, &quot;reason&quot;: &quot;...&quot;},</span></span>
<span class="line"><span>  &quot;conciseness&quot;: {&quot;score&quot;: 5, &quot;reason&quot;: &quot;...&quot;},</span></span>
<span class="line"><span>  &quot;friendliness&quot;: {&quot;score&quot;: 4, &quot;reason&quot;: &quot;...&quot;},</span></span>
<span class="line"><span>  &quot;overall&quot;: 4,</span></span>
<span class="line"><span>  &quot;fatal_errors&quot;: []</span><span>  // 如果有编造信息等致命错误，列在这里</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br></div></div><div class="warning custom-block"><p class="custom-block-title">LLM-as-a-Judge 的三个陷阱</p><p><strong>陷阱一：裁判模型自身的偏见。</strong> GPT-4 倾向于给&quot;更长、更详细&quot;的回答更高分——但用户其实讨厌啰嗦。对策：在评分标准中明确&quot;简洁是优点&quot;，并用人工校准一个子集来验证 GPT-4 的评分是否与人类评分趋势一致。</p><p><strong>陷阱二：裁判模型对&quot;自己人&quot;更宽容。</strong> GPT-4 评估 GPT-4 的回答时，有时会比对其他模型的回答更宽松。对策：如果可能，用不同的裁判模型交叉验证（如用 Claude 评估 GPT-4 的输出）。如果只能用一个裁判模型，至少做 10% 人工抽查验证。</p><p><strong>陷阱三：位置偏差。</strong> 如果让裁判模型同时比较两个回答（A vs B），它可能天然倾向第一个或第二个。对策：随机交换顺序做两次，取平均；或者用单条评分而非配对比较。</p></div><h3 id="_2-3-评测集构建——你的-黄金标准" tabindex="-1">2.3 评测集构建——你的&quot;黄金标准&quot; <a class="header-anchor" href="#_2-3-评测集构建——你的-黄金标准" aria-label="Permalink to &quot;2.3 评测集构建——你的&quot;黄金标准&quot;&quot;">​</a></h3><p>评测集是 AI 产品最重要的资产之一。构建方法：</p><p><strong>Step 1：确定覆盖范围</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>要求</th></tr></thead><tbody><tr><td>场景覆盖</td><td>覆盖所有核心场景（退货/物流/优惠券），每种至少 50 条</td></tr><tr><td>难度分布</td><td>简单 40% + 中等 40% + 困难 20%</td></tr><tr><td>边界 Case</td><td>至少 20% 的样本是容易出错的边界场景</td></tr><tr><td>新鲜度</td><td>评测集中必须有 30% 的样本不在任何训练数据中</td></tr></tbody></table><p><strong>Step 2：标注&quot;标准答案&quot;</strong></p><p>给每条评测样本标注的不是简单的&quot;对/错&quot;，而是：</p><ul><li><strong>标准答案</strong>：正确的回答应该包含哪些要点</li><li><strong>常见错误模式</strong>：这个 Case 上模型容易犯哪类错误</li><li><strong>可接受范围</strong>：哪些回答虽然不够完美但可以算作通过</li></ul><p><strong>Step 3：版本管理</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>eval_set/</span></span>
<span class="line"><span>├── v1.0_202501_baseline.json    # 首批 200 条</span></span>
<span class="line"><span>├── v1.1_202503_补充退货.json     # 补充 50 条退货边界 Case</span></span>
<span class="line"><span>├── v1.2_202505_客服V2上线.json   # 新增 30 条多轮对话 Case</span></span>
<span class="line"><span>└── changelog.md                  # 每次更新的原因和变化</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><div class="tip custom-block"><p class="custom-block-title">实战经验</p><p>评测集需要定期&quot;换血&quot;。如果模型在某类 Case 上已经达到 98% 准确率，这些 Case 的区分度就很低了——保留 10 条做回归测试即可，其他替换为新的困难 Case。评测集不是越大越好，而是<strong>越新、越有区分度</strong>越好。</p></div><hr><h2 id="三、人工评估——比自动化评估更重要的环节" tabindex="-1">三、人工评估——比自动化评估更重要的环节 <a class="header-anchor" href="#三、人工评估——比自动化评估更重要的环节" aria-label="Permalink to &quot;三、人工评估——比自动化评估更重要的环节&quot;">​</a></h2><h3 id="_3-1-为什么自动化评估不能替代人工评估" tabindex="-1">3.1 为什么自动化评估不能替代人工评估 <a class="header-anchor" href="#_3-1-为什么自动化评估不能替代人工评估" aria-label="Permalink to &quot;3.1 为什么自动化评估不能替代人工评估&quot;">​</a></h3><p>自动化指标告诉你&quot;模型得分是多少&quot;，人工评估告诉你**&quot;用户实际感受如何&quot;**。两者可能严重不一致。</p><details class="details custom-block"><summary>真实案例</summary><p>我们做过一次实验：同一批回答，LLM-as-a-Judge 打分 4.2/5，但真实用户满意度只有 3.6/5。差距的原因：LLM 裁判偏好&quot;全面、详细的回答&quot;，而用户觉得&quot;太啰嗦了，我只是想知道退款到账时间&quot;。</p></details><h3 id="_3-2-人工评估的标准流程" tabindex="-1">3.2 人工评估的标准流程 <a class="header-anchor" href="#_3-2-人工评估的标准流程" aria-label="Permalink to &quot;3.2 人工评估的标准流程&quot;">​</a></h3><p><strong>流程设计</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>评估准备 → 评估员培训 → 校准轮 → 正式评估 → 一致性检验 → 结果分析</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>评估问卷设计示例</strong>：</p><table tabindex="0"><thead><tr><th>评估维度</th><th>问题</th><th>评分标准</th></tr></thead><tbody><tr><td>正确性</td><td>回答的内容是否准确无误？</td><td>1-5，5=完全正确</td></tr><tr><td>完整性</td><td>是否回答了用户关心的所有方面？</td><td>1-5，5=完全覆盖</td></tr><tr><td>简洁性</td><td>是否用最少的话把事说清楚？</td><td>1-5，5=非常精炼</td></tr><tr><td>有用性</td><td>用户看完后问题是否被解决了？</td><td>是/否/部分</td></tr></tbody></table><p><strong>评估员校准</strong>：</p><ul><li>准备 20 条&quot;金标准样本&quot;——已有正确答案且经多方确认的</li><li>评估员先独立打分 → 对比与金标准的差异 → 讨论不一致的打分 → 达成共识</li><li>正式评估开始前确保评估员间 Kappa ≥ 0.7</li></ul><h3 id="_3-3-评估规模与频率" tabindex="-1">3.3 评估规模与频率 <a class="header-anchor" href="#_3-3-评估规模与频率" aria-label="Permalink to &quot;3.3 评估规模与频率&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>评估频率</th><th>每次样本量</th><th>评估员数量</th></tr></thead><tbody><tr><td>POC/验证</td><td>一次性</td><td>50-100 条</td><td>1-2 人（可接受非正式）</td></tr><tr><td>上线前</td><td>一次性</td><td>200-500 条</td><td>2-3 人（必须双人交叉）</td></tr><tr><td>上线后日常</td><td>双周</td><td>100 条</td><td>2 人</td></tr><tr><td>大版本迭代</td><td>上线前</td><td>300-500 条</td><td>3 人</td></tr></tbody></table><hr><h2 id="四、线上-a-b-测试——终极评判标准" tabindex="-1">四、线上 A/B 测试——终极评判标准 <a class="header-anchor" href="#四、线上-a-b-测试——终极评判标准" aria-label="Permalink to &quot;四、线上 A/B 测试——终极评判标准&quot;">​</a></h2><h3 id="_4-1-a-b-测试设计六要素" tabindex="-1">4.1 A/B 测试设计六要素 <a class="header-anchor" href="#_4-1-a-b-测试设计六要素" aria-label="Permalink to &quot;4.1 A/B 测试设计六要素&quot;">​</a></h3><ol><li><strong>假设</strong>：AI 客服能让人工转接率降低 ≥ 30%（不是&quot;提升体验&quot;——太模糊了没法测）</li><li><strong>指标</strong>：主指标是人工转接率（OEC），辅助指标是用户满意度、响应时间</li><li><strong>样本量</strong>：基于预期效应量和统计功效计算（见 4.2）</li><li><strong>随机分流</strong>：用户级别的随机分流（按 user_id hash），避免 session 内的交叉污染</li><li><strong>实验周期</strong>：至少覆盖一个完整的周——包含工作日和周末的数据波动</li><li><strong>护栏指标</strong>：如果用户满意度下降 &gt; 0.3 分 → 自动终止实验（&quot;不能为了效率牺牲体验&quot;）</li></ol><h3 id="_4-2-样本量速算表" tabindex="-1">4.2 样本量速算表 <a class="header-anchor" href="#_4-2-样本量速算表" aria-label="Permalink to &quot;4.2 样本量速算表&quot;">​</a></h3><p>样本量取决于三个因素：基线转化率、最小可检测效应（MDE）、显著性水平和统计功效。</p><table tabindex="0"><thead><tr><th>基线率</th><th>MDE（最小可检测提升）</th><th>每组所需样本数</th></tr></thead><tbody><tr><td>50%</td><td>5 个百分点</td><td>~1,600</td></tr><tr><td>50%</td><td>10 个百分点</td><td>~400</td></tr><tr><td>20%</td><td>5 个百分点</td><td>~1,000</td></tr><tr><td>20%</td><td>3 个百分点</td><td>~2,800</td></tr><tr><td>5%</td><td>2 个百分点</td><td>~3,500</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">实战速记</p><p>大多数 AI 产品的核心指标基线在 20-50%，最小预期提升在 5-10 个百分点，所以<strong>每组 800-1600 样本是最常见的需求</strong>。按日活 × 实验比例估算实验天数。</p></div><h3 id="_4-3-结果解读——别被-p-值骗了" tabindex="-1">4.3 结果解读——别被 p 值骗了 <a class="header-anchor" href="#_4-3-结果解读——别被-p-值骗了" aria-label="Permalink to &quot;4.3 结果解读——别被 p 值骗了&quot;">​</a></h3><table tabindex="0"><thead><tr><th>常见误读</th><th>正确理解</th></tr></thead><tbody><tr><td>&quot;p=0.04，说明实验组比对照组好&quot;</td><td>&quot;p=0.04 说明如果实际上没有差异，仅有 4% 的概率观察到当前这么大的差异&quot;——不等于&quot;实验组更好&quot;</td></tr><tr><td>&quot;p=0.06，说明没有效果&quot;</td><td>&quot;未达到统计显著性 ≠ 没有效果&quot;——可能样本量不够或效应量太小</td></tr><tr><td>&quot;多个指标都有提升，p 值都 &lt; 0.05&quot;</td><td>&quot;同时测 10 个指标，即使完全没效果，也有 40% 的概率至少一个指标 p &lt; 0.05&quot;——需要多重比较校正（Bonferroni 是最保守的）</td></tr></tbody></table><p><strong>PM 的 A/B 测试自查清单</strong>：</p><ul><li>[ ] 样本量是否在实验开始前就计算好了？（不要中途 peek）</li><li>[ ] 有没有预注册实验计划？（避免&quot;测了 10 个指标然后只报告显著的&quot;）</li><li>[ ] 效应量是否有业务意义？（2% 的提升即使显著可能也不值得上线）</li><li>[ ] 是否检查了分组的随机性？（A/B 组用户在关键特征上是否分布一致）</li></ul><hr><h2 id="五、持续监控——上线不是结束" tabindex="-1">五、持续监控——上线不是结束 <a class="header-anchor" href="#五、持续监控——上线不是结束" aria-label="Permalink to &quot;五、持续监控——上线不是结束&quot;">​</a></h2><h3 id="_5-1-核心监控指标看板" tabindex="-1">5.1 核心监控指标看板 <a class="header-anchor" href="#_5-1-核心监控指标看板" aria-label="Permalink to &quot;5.1 核心监控指标看板&quot;">​</a></h3><table tabindex="0"><thead><tr><th>层级</th><th>指标</th><th>监控频率</th><th>告警阈值</th></tr></thead><tbody><tr><td><strong>模型层</strong></td><td>准确率、各类别 F1</td><td>每日</td><td>连续 3 天下降 &gt; 5%</td></tr><tr><td><strong>数据层</strong></td><td>输入特征 PSI</td><td>每周</td><td>PSI &gt; 0.25</td></tr><tr><td><strong>业务层</strong></td><td>人工转接率、满意度</td><td>每日</td><td>连续 5 天下降 &gt; 10%</td></tr><tr><td><strong>成本层</strong></td><td>API 调用量、推理延迟</td><td>实时</td><td>延迟 P99 &gt; 5s</td></tr></tbody></table><h3 id="_5-2-退化检测的-sop" tabindex="-1">5.2 退化检测的 SOP <a class="header-anchor" href="#_5-2-退化检测的-sop" aria-label="Permalink to &quot;5.2 退化检测的 SOP&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>触发告警 → 确认真实下降（排除波动）→ 隔离原因（模型/数据/业务变化？）</span></span>
<span class="line"><span>    → 如影响业务指标 → 回滚到上一稳定版本（先止血）</span></span>
<span class="line"><span>    → 根因分析 → 修复 → 重新上线 → 回检监控</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><hr><h2 id="六、面试追问合集" tabindex="-1">六、面试追问合集 <a class="header-anchor" href="#六、面试追问合集" aria-label="Permalink to &quot;六、面试追问合集&quot;">​</a></h2><h3 id="q1-你怎么衡量一个生成式-ai-产品的质量" tabindex="-1">Q1: 你怎么衡量一个生成式 AI 产品的质量？ <a class="header-anchor" href="#q1-你怎么衡量一个生成式-ai-产品的质量" aria-label="Permalink to &quot;Q1: 你怎么衡量一个生成式 AI 产品的质量？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>用三层评估框架：</p><p><strong>L1：自动化离线评估（快速、批量、可重复）</strong></p><ul><li>传统指标（分类场景的 F1）</li><li>LLM-as-a-Judge（多维度评分：准确性、完整性、简洁性、友好度）</li><li>回归测试（确保新版本不在旧 Case 上退步）</li></ul><p><strong>L2：人工评估（定性校准）</strong></p><ul><li>每两周抽取 100 条做人工打分</li><li>重点关注 LLM-as-a-Judge 和人工评分的一致性——如果偏离 &gt; 0.5 分，说明评估 Prompt 需要调整</li></ul><p><strong>L3：线上业务指标（终极标准）</strong></p><ul><li>A/B 测试验证核心业务指标</li><li>用户满意度 + 转人工率 + 响应时长</li></ul><p>只依赖任何一层都会出问题。LLM 裁判有偏见，人工评估太贵太慢，线上 A/B 太慢且受噪声干扰——三层交叉验证才是可靠的。</p></details><h3 id="q2-llm-as-a-judge-的评分和人评不一致怎么办" tabindex="-1">Q2: LLM-as-a-Judge 的评分和人评不一致怎么办？ <a class="header-anchor" href="#q2-llm-as-a-judge-的评分和人评不一致怎么办" aria-label="Permalink to &quot;Q2: LLM-as-a-Judge 的评分和人评不一致怎么办？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>不一致是正常的，需要系统性排查：</p><ol><li><p><strong>确认不一致的方向和模式</strong>：LLM 系统性偏高还是偏低？在哪些维度上分歧最大？是 LLM 太宽容（准确性给 4 分但人评觉得明显有错）还是 LLM 太苛刻（嫌回答不够全面但用户只需要 Yes/No）？</p></li><li><p><strong>调整评估 Prompt 中的评分标准</strong>：如果 LLM 评分偏高——在 Prompt 里加&quot;请严格评分，只有完全符合要求才能给 5 分&quot;。如果 LLM 对简洁性理解有偏差——在评分标准中明确定义&quot;简洁性的满分标准是&#39;用最少的话讲清楚问题的所有要点，不添加无关信息&#39;&quot;。</p></li><li><p><strong>加入校准样本</strong>：在评测 Prompt 里放 2-3 个&quot;校准示例&quot;——展示人类对某些回答的评分——让 LLM 校准自己的评分标准。</p></li><li><p><strong>如果上面都做了还是不一致</strong>：承认 LLM 裁判在这个维度上的局限性，对该维度增加人工评分的权重，或在关键决策时避免单独依赖 LLM 评估。</p></li></ol></details><h3 id="q3-如何设计一个评测集来确保新-prompt-不会引入退化" tabindex="-1">Q3: 如何设计一个评测集来确保新 Prompt 不会引入退化？ <a class="header-anchor" href="#q3-如何设计一个评测集来确保新-prompt-不会引入退化" aria-label="Permalink to &quot;Q3: 如何设计一个评测集来确保新 Prompt 不会引入退化？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>这是&quot;回归测试&quot;思维——你在更新 Prompt 时，新的 Case 效果好了，但不能让旧的 Case 效果变差。</p><ol><li><p><strong>构建回归基准集</strong>：从线上收集 200 条&quot;当前版本处理得很好&quot;的 Case（人工确认正确率 &gt; 95%），这 200 条就是你的&quot;不能退步&quot;名单。</p></li><li><p><strong>每次 Prompt 更新后</strong>：先跑回归基准集——任何一条 Case 从&quot;正确&quot;变成&quot;错误&quot;都属于退化，需要<strong>强制修复</strong>才能上线。</p></li><li><p><strong>建立&quot;纠错样本库&quot;</strong>：把历史上让你翻过车的 Case 集中管理。每次 Prompt 更新时确保这些已知的坑没有被重新踩到。</p></li></ol><p>这个方法我实践过——有一次我们改 Prompt 让模型在 90% 的场景下表现更好了，但回归基准集里有一条&quot;用户问退货但用的是广东话口语&quot;的 Case 从正确变成了错误。没有回归测试就直接上线的话，广东地区用户会收到错误回答——这个影响范围虽然小（约 3% 用户），但体验伤害很大。</p></details><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="./product-design">AI 产品设计</a></li><li><a href="./data-model-management">数据与模型管理</a></li><li><a href="./case-study">实战案例：智能客服全流程</a></li><li><a href="./interview">AI PM 面试高频题</a></li></ul>`,64))])}const _=l(c,[["render",h]]);export{B as __pageData,_ as default};
